INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (474, 'single', '23. (2) 某一計算機執行一個指令的速度為100 奈秒（nanosecond），相當於多 少秒？', '1×10 -9 秒,1×10- 7 秒,1×10 -6 秒,1×10 -5 秒 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (475, 'single', '24. (1) 下列哪一種裝置不屬於輔助記憶體？', 'SRAM,SSD（Solid-State Disk）,HDD（Hard Disk Drive）,隨身碟 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (476, 'single', '25. (3) 某一EPROM 記憶體IC，其位址接腳為5Bits，而每一位址的容量為 1Byte，則此IC 的記憶總容量為', '32Bits,128Bits,256Bits,512Bits ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (477, 'single', '26. (3) 微處理器所能執行的語言為', 'BASIC,C 語言,機器語言,組合語 言 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (478, 'single', '27. (2) 2764 為一8K×8 的記憶體IC，其位址線共有', '12 條,13 條,14 條,15 條 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (479, 'single', '28. (3) 欲規劃56K×16bits 的記憶區時，需使用幾顆8K×8 的2764？', '7,8,14,16 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (480, 'single', '29. (2) 下列敘述何者錯誤？', 'CPU 由ALU、ACC 與控制單元等組成,堆疊是 採用先進先出方式,資料匯流排為雙向性,旗標暫存器是指示ALU 運 算後的情況 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (481, 'single', '30. (4) 有關DRAM 特性的敘述，下列何者錯誤？', '單一晶片容量較大,需要 有復新（Refresh）動作,包裝上較少的外部接腳,有較佳的存取速 度 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (482, 'single', '31. (3) 下列哪一項不是使用單晶片（Single Chip）微電腦元件的優點？', '硬體 製作較簡單,料件採購及管理較單純,系統有較大的擴充性,軟體程 式可以有較高的防讀保護 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (483, 'single', '32. (1) 微電腦系統以RS-232C 串列方式傳輸資料到周邊裝置，其串列傳輸格式 為一位元啟始位元，8 位元資料，一位元同位元，2 位元結束位元，若以 2400 鮑率（Baud-rate）連續傳送100 個位元組（Byte）之資料，所需的 時間約為', '0.5 秒,2.4 秒,100 秒,2400 秒 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (484, 'single', '33. (2) 在中斷式I/O 中，當I/O 裝置需要作I/O 服務處理時，會以何種信號來 通知CPU，以進行I/O 傳輸服務？', '讀寫線（R/W）,中斷要求線 （IRQ）,中斷認知線（IACK）,晶片選擇線（CS） ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (485, 'single', '34. (4) 十六位元的位址線匯流排，最大可支援到多少個記憶體位址？', '16 個,1024 個,4096 個,65536 個 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (486, 'single', '35. (3) 有一個典型的記憶體IC 其容量為1Meg×8 位元（bits），則其位址線 （address bus）有幾條？', '10 條,16 條,20 條,24 條 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (487, 'single', '36. (2) DMA（Direct Memory Access）處理速度快，適合大量資料傳送，主要 原因為', '不必使用位址線,不必經由CPU 傳送,使用較多的控制線,使用較多的資料線 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (488, 'single', '37. (2) 某電腦顯示器的解析度為1240×1024 點，且為256 色，則該電腦須大約 使用多少記憶體來控制顯示器？', '1.3Mbits,1.3MBytes,320Mbits,320MBytes ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (489, 'single', '38. (3) CMOS IC 比TTL IC 具有較低的功率消耗，但其最大缺點是響應時間較 長，此段時間通稱為', '上升時間,下降時間,傳遞延遲,作業時間 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (490, 'single', '39. (2) 微處理器所運作的內部工作頻率產生，下列敘述何者正確？', '等於外頻,外頻乘於倍數,內頻乘於倍數,外頻除於倍數 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (491, 'single', '40. (1) RISC 擁有一簡化的控制單元，典型的單一指令執行需多少機械週期 （machine cycle）？', '1,2,3,4 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (492, 'single', '41. (4) 下列何種類型的PROM 可以不需要從腳座上移開，即可進行清除或更新 其內部儲存資料？', 'UV-EPROM,EPROM,OTPROM,E2PROM ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (493, 'single', '42. (3) 下列何者為熱插拔（hot-pluggable）裝置介面？', 'PCI,COM,USB,LPT ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (494, 'single', '43. (4) 系統中的韌體（firmware）一般不適合儲存於下列哪種記憶體中？', 'EEPROM,EPROM,PROM,RAM ', '3', '');
