INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (496, 'single', '45. (3) 下列印表機何者印字速度最高？', '菊輪式,噴墨式,雷射式靜電複印,感光型 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (497, 'single', '46. (1) 若顯示字型為7×9 陣列，且螢幕每列（Row）可顯示80 字，則每條掃描 線有幾個點（dot）？', '560,640,720,800 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (498, 'single', '47. (4) 密閉式磁碟機在運轉時，磁頭是靠何種方式達到上浮的目的？', '油壓,機械原理,彈簧,空氣動力 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (499, 'single', '48. (4) 磁碟機之記錄密度與何者無關？', '磁片密度,磁頭材質,記錄方式,迴轉速度 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (500, 'single', '49. (2) 鍵彈跳（key bounce）一般值為', '0.1～2ms,1～20ms,10～200ms,200ms 以上 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (501, 'single', '50. (3) 下列何者不是輸入裝置？', '滑鼠,光筆,語音合成器,數位板 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (502, 'single', '51. (2) 1200Baud Rate 的RS-232C 串列傳送，每秒約傳多少位元組（Byte）？', '12,120,1200,無限 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (503, 'single', '52. (4) 下列何種為撞擊式印字機？', '熱感式,靜電式,噴墨式,點矩陣式 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (504, 'single', '53. (2) 影像掃描器的解析度單位為', 'TPI,DPI,BPS,LPI ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (505, 'single', '54. (2) 下列何種顯示器，耗電量最少？', 'LED,LCD,PLASMA,CRT ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (506, 'single', '55. (4) 下列何種顯示卡之彩色解析度最好？', 'CGA,MGA,EGA,VGA ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (507, 'single', '56. (3) 一彩色顯示卡上有128K 之顯示記憶體，若其解析度為600×400 點，則 每一點之色彩至多有多少色？', '2,4,16,256 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (508, 'single', '57. (1) 輸入不規則圖形最好採用何種設備？', '掃描器,滑鼠,光筆,觸控螢 幕 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (509, 'single', '58. (2) 微電腦之自動演奏與電子樂器間的DATA 可互相交換的共通介面電路， 稱之為何？', 'SCSI,MIDI,ASIC,RISC ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (510, 'single', '59. (3) 每一台PC 都透過網路卡接在一起，在網路的末端接有一個電阻以避免 訊號干擾，且電腦在每次傳送資料時要作衝撞檢查（collision detection）才不會造成傳輸衝突，這種網路稱為', 'Ring Network,Star Network,Bus Network,Tree Network ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (511, 'single', '60. (4) 下列哪一項不是兩台遠距離電腦之間互相通訊的必要條件？', '兩台電腦 都要裝有modem,在相同的傳輸速率下,使用相同的通訊協定,使用 相同廠牌的電腦 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (512, 'single', '61. (4) 微電腦控制A/D 轉換裝置將類比信號轉換為數位信號時，下列哪一步驟 不屬於轉換過程？', '類比信號送到A/D 裝置,電腦送出起始轉換信號 到A/D 裝置,A/D 送回終止轉換信號給電腦,電腦送出轉換過的數位 信號到A/D 裝置 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (513, 'single', '62. (1) 有關8255 可程式I/O 介面IC 的敘述，下列何者錯誤？', '有兩個獨立的 8bitsI/O 埠,CPU 可讀取8255 各埠的資料,CPU 可將資料送到8255 各I/O 埠,CPU 利用read 和write 來控制對8255 的讀或寫 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (514, 'single', '63. (2) 數據機在兩部設備中，傳送資料時，兩個方向可同時交換資料的為下列 哪種模式？', '單工（simplex）,全雙工（full duplex）,半雙工（half duplex）,半單工（half simplex） ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (515, 'single', '64. (3) 在多芯電纜中，由於導線間電容耦合而造成互相干擾的現象稱為', '電磁 干擾,雜訊干擾,串音干擾,輻射干擾 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (516, 'single', '65. (4) 採用7 個bit 的交換碼，且以(1000001)2 即41H 表示"A"的交換碼是哪一 種碼？', 'IA5（International Alpheabet 5）,CCCII（Chinese Character Codefor Information Interchange）,EBCDIC（Extended Binary Coded Decimal Interchange Code）,ASCII（American Standard Codefor Information Interchange） ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (517, 'single', '66. (3) 下列哪一種傳輸（transmission）線對電腦的電磁有較高的抗干擾性？', '同軸電纜,雙絞線,光纖電纜,多芯同軸電纜 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (518, 'single', '67. (1) 下列何者在資料傳輸時，資料發送方和接收方相互地將己方已完成的情 況告訴對方，以確保資料傳輸的正確性？', '交握（handshake）,確認 （confirm）,查詢（inquire）,輪詢（polling） ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (519, 'single', '68. (4) 國際標準組織（ISO）的資料通訊協定有七層，其中最高層次是擔任對 使用者直接服務的任務，其為哪一層？', '實體層,傳輸層,會議層,應用層 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (520, 'single', '69. (2) 磁碟機的讀寫頭已到達所需讀寫資料位置，而控制邏輯卻尚未準備好進 行傳送，因此磁碟必需繼續旋轉，這種情形稱之為何？', '資料漏失 （data loss）,資料遲到（data late）,傳輸延遲,磁碟故障 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (521, 'single', '70. (2) 從字元產生器的ROM 或EPROM 晶片中，讀取ASCII 碼的字形圖樣， 再送到由許多電磁鐵控制的針狀印字頭上的是哪一型印表機？', '噴墨式,點矩陣,熱感式,雷射 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (522, 'single', '71. (2) 下列何者屬於非同步傳輸的特性？', '採用並列方式傳輸字元,傳輸的 字元夾在起始字元和終止字元之間,在傳輸中，資料不可間斷,利用 交握信號來確定傳輸資料的正確性 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (523, 'single', '72. (2) 一般列表機採用的介面為', 'RS-232C 或IEEE-488 介面,USB 或 Centronics 介面,RS-232C 或GPIB 介面,GPIB 或Centronics 介面 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (524, 'single', '73. (1) 具有偵錯和校正能力的編碼系統為', '漢明（Hamming）碼,BCD 碼,ASCII 碼,EBCDIC 碼 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (525, 'single', '74. (3) 有關ISDN 之敘述何者錯誤？', '採用數位傳輸與數位交換技術,共同傳 輸設備與交換系統,通信頻道容量小，減少傳輸時間,容許各種不同 類型的終端設備相互通訊 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (526, 'single', '75. (4) 可重複多次讀寫動作的光碟片為', 'CD-ROM 光碟,CD-R 光碟,WORM 光碟,CD-RW 光碟 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (527, 'single', '76. (3) 下列何者是使用公眾電話網路（PSTN）上網際網路（Internet）的必要 裝備？', '滑鼠（Mouse）,光碟機,數據機（Modem）,音效卡 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (528, 'single', '77. (4) 下列何項不是造成網際網路（Internet）檔案傳輸速度緩慢的原因？', '低速數據機,線路品質不佳,伺服機負載過重,交換機負載過重 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (529, 'single', '78. (4) 以軟體掃描式在發光二極體（LED）上顯示數值或資料時，至少需要在 多少時間內更新一次，方不會讓查看者感到有閃爍現象？', '1/2 秒,1/4 秒,1/8 秒,1/16 秒 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (530, 'single', '79. (4) 下列對PCI 匯流排的敘述，何者錯誤？', '個人電腦及工作站的輸出輸入 匯流排,時鐘頻率為33MHz,最大傳輸速度為133MHz,匯流排寬為 16 位元 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (531, 'single', '80. (1) 下列何者不是IEEE-1394 介面的優點？', '資料傳輸速度只有400Mbit/s,支援熱插拔（Hot Plug）,具隨插即用功能,最多可連接達63 台周 邊機器 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (532, 'single', '81. (4) 下圖之符號為', '印表機,紅外線,區域網路,通用序列 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (533, 'single', '82. (2) 下列何者不是USB 介面的特性？', '即插即用,只能接64 個周邊,熱 插拔,安裝容易 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (534, 'single', '83. (4) 個人電腦的硬碟如採LBA（Logical Block Address）規格，其儲存資料 之單一邏輯硬碟最大容量為', '2.1GB,16GB,64GB,128GB ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (535, 'single', '84. (3) 依製作及技術而言，下列何者不是觸控式顯示螢幕的類型？', '電阻式,電容式,電感式,紅外線式 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (536, 'single', '85. (4) 有關同步與非同步傳輸，下列何者正確？', '在非同步傳輸中，只要資料 位元，不必加控制位元,同步傳輸比較慢,傳送和接收的傳送率 （Baud rate）不須一樣,非同步傳輸資料通常傳輸量較小 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (581, 'single', '1. (1) 虛擬指令（pseudo instruction）之功用為', '作編譯指示,供註解之用,產生機器碼,可加快編譯速度 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (582, 'single', '2. (3) 巨集（Macro）指令可', '加快執行速度,加速編譯速度,方便程式撰寫,節省記憶體空間 ', '2', '');
