INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (662, 'single', '1. (2) 有關匯流排網路架構之說明，下列何者錯誤？', '採用廣播方式傳遞資料,同一個時間允許多個節點廣播傳送,使用同軸電纜,同軸電纜兩端要 加終端電阻，使訊號送到最終兩端時終止 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (663, 'single', '2. (3) 有關星狀網路（star network）架構之說明，下列何者錯誤？', '一般使用 雙絞線連接，需使用集線器或交換式集線器來連接電腦設備,只有中央 控制設備故障，整個網路才會癱瘓,當集線器的連接埠不足時，不可以 使用其他的集線器串接,任一節點傳送資料，都必須經由集線器或交換 式集線器送到目的節點 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (664, 'single', '3. (4) 有關環狀網路（ring network）架構之說明，下列何者錯誤？', '可使用雙 絞線、同軸電纜、光纖進行連接,使用多站存取單元（MAU 或 MSAU），類似集線器將所有電腦以環型方式串接起來,以節點（電 腦）取得記號封包來決定傳遞資料的優先順序,當任一節點故障，整個 網路仍可繼續運作 ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (665, 'single', '4. (4) 開放式系統連結（OSI）參考模型七層網路架構中，哪一層是主要負責傳 送路徑的選擇？', '資料鏈結層,會議層,實體層,網路層 ', '3', '');
