INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (668, 'single', '7. (4) 開放式系統連結（OSI）參考模型七層網路架構中，哪一層是與硬體密切 相關？', '會議層,資料鏈結層,網路層,實體層 ', '3', '');
