INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (670, 'single', '9. (1) 網路卡上的MAC 位址是屬於開放式系統連結（OSI）參考模型七層網路 架構中的哪一層？', '資料鏈結層,實體層,網路層,應用層 ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (671, 'single', '10. (3) TCP/IP 協定中，下列敘述何者正確？', 'FTP 用來提供全球資訊網 （WWW）服務的通訊協定,HTTP 用來提供檔案傳輸服務的通訊協定,SMTP 用來提供電子郵件傳送服務的通訊協定,POP3 用來提供動態分配 IP 服務的通訊協定 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (672, 'single', '11. (2) TCP/IP 協定中，下列敘述何者正確？', 'ARP 是用來將IP 位址轉成實體 位址,Telnet 用來提供用戶端模擬終端機登入遠端伺服器服務的通訊協 定,DHCP 與TCP 協定一樣將資料傳送到接收端，但以非連接導向方式 傳送,UDP 用來提供動態分配IP 服務的通訊協定 ', '1', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (673, 'single', '12. (3) Wi-Fi 使用的通訊協定是', 'IEEE-802.3,IEEE-802.4,IEEE-802.11x,IEEE-802.16x ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (674, 'single', '13. (1) Wi-Fi 的通訊協定中，使用頻率5.0GHz、傳輸速度54Mbps、傳輸距離 100M 的通訊協定為', 'IEEE-802.11a,IEEE-802.11b,IEEE-802.11g,IEEE-802.11n ', '0', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (675, 'single', '14. (1) 有關藍牙（Bluetooth）通訊技術敘述，下列何者正確？', '協定名稱為 IEEE-802.15.1,使用頻率為5.0GHz,一般傳輸距離高於100 公尺,傳 輸速度為100Mbps ', '0', '');
