INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (681, 'single', '20. (3) 有關IPv4 與IPv6 的敘述，下列何者錯誤？', 'IPv4 的位址有32 位元,IPv6 的位址有128 位元,IPv4 轉化為IPv6 時，只要在前方加入96 位元 的0 即可,IPv6 的位址表示時，分成八組 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (682, 'single', '21. (3) 有關Web 2.0 的敘述，下列何者錯誤？', '以使用者為中心來創造、協 作，如維基百科,使用者主導網路資源，成為內容的分享及提供者,使 用者能主動獲取或是系統自動推薦相關的內容以取代無效的廣告,有別 於Web 1.0 的靜態呈現，Web 2.0 強調高度網路互動 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (683, 'single', '22. (3) 有關應用於電子郵件之協定敘述，下列何者正確？', 'SMAP 有提供伺服 端郵件管理指令，安全性佳,POP3 非Client-Server 架構,IMAP、 SMTP 及POP3 皆為郵件協定,POP3 不占客戶端空間，適合四處活動的 使用者 ', '2', '');
