INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (686, 'single', '25. (4) 對於802.11 無線區域網路之標準規格，資料傳輸率最高的為何？', '802.11a,802.11b,802.11g,802.11n ', '3', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (687, 'single', '26. (3) 網路安全中，有關防火牆（Firewall）的特性，下列何者錯誤？', '所有從 內部網路（Internal Network）能往外部網路（External Network）的資料 流，都必須經防火牆,所有從外部網路通往內部網路的資料流，都必需 經過防火牆,使用防火牆可以加強對電腦病毒的防範,只有符合內部網 路安全政策的資料流，才可以通過防火牆 ', '2', '');
INSERT INTO `questions` (`id`, `type`, `question`, `options`, `answer`, `image`) VALUES (688, 'single', '27. (3) 網路設備收到IP 位址後，一般會先找出其等級再套用標準遮罩。當收到 位址「(11000001 10000011 00011011 11111111) 2」時，以分級定址而 言，屬於哪一等級？', 'A 級,B 級,C 級,D 級 ', '2', '');
